await runCheck("min-notional exit helpers detect Binance filter errors and resolve demo flag", async () => {
  const err = new Error("x");
  err.payload = { code: -1013, msg: "Filter failure: MIN_NOTIONAL" };
  assert.equal(isBinanceMinNotionalFilterError(err), true);
  assert.equal(isBinanceMinNotionalFilterError(new Error("unrelated")), false);
  assert.equal(resolveAllowSyntheticMinNotionalExit({ allowSyntheticMinNotionalExit: true, botMode: "live" }), true);
  assert.equal(
    resolveAllowSyntheticMinNotionalExit({ allowSyntheticMinNotionalExit: false, botMode: "paper", paperExecutionVenue: "binance_demo_spot" }),
    false
  );
  assert.equal(
    resolveAllowSyntheticMinNotionalExit({ allowSyntheticMinNotionalExit: null, botMode: "paper", paperExecutionVenue: "binance_demo_spot" }),
    true
  );
  assert.equal(resolveAllowSyntheticMinNotionalExit({ botMode: "paper", paperExecutionVenue: "internal" }), false);
});

