await runCheck("candidate execution ranking uses deterministic tie-breaks and exposes cohort metadata", async () => {
  const ranked = annotateCandidateExecutionRanking([
    {
      symbol: "BTCUSDT",
      score: { probability: 0.61, confidence: 0.58 },
      strategySummary: { activeStrategy: "ema_trend" },
      decision: {
        allow: true,
        opportunityScore: 0.62,
        rankScore: 0.54,
        threshold: 0.56,
        approvalReasons: ["trend_regime_support"]
      }
    },
    {
      symbol: "ETHUSDT",
      score: { probability: 0.63, confidence: 0.57 },
      strategySummary: { activeStrategy: "ema_trend" },
      decision: {
        allow: true,
        opportunityScore: 0.62,
        rankScore: 0.59,
        threshold: 0.55,
        approvalReasons: ["session_liquidity_support"]
      }
    },
    {
      symbol: "SOLUSDT",
      score: { probability: 0.58, confidence: 0.49 },
      strategySummary: { activeStrategy: "bollinger_squeeze" },
      decision: {
        allow: false,
        opportunityScore: 0.49,
        rankScore: 0.44,
        threshold: 0.57,
        approvalReasons: []
      }
    }
  ].sort((left, right) => compareCandidateExecutionRank(left, right)));

  assert.equal(ranked[0].symbol, "ETHUSDT");
  assert.equal(ranked[0].decision.executionRanking.rankPosition, 1);
  assert.equal(ranked[0].decision.executionRanking.allowedRankPosition, 1);
  assert.equal(ranked[1].decision.executionRanking.rankPosition, 2);
  assert.equal(ranked[1].decision.executionRanking.allowedRankPosition, 2);
  assert.equal(ranked[2].decision.executionRanking.allowedRankPosition, null);
  assert.equal(ranked[0].decision.executionRanking.cohortSize, 3);
  assert.equal(ranked[0].decision.executionRanking.allowedCohortSize, 2);
  assert.equal(ranked[1].decision.executionRanking.lostToLeader.symbol, "ETHUSDT");
  assert.ok(ranked[1].decision.executionRanking.lostToLeader.reasons.includes("lower_rank_score"));
  assert.deepEqual(ranked[0].decision.executionRanking.topReasons, ["session_liquidity_support", "ema_trend_setup"]);
});

