await runCheck("run cli marks once command successful even when the cycle returns no_allowed_candidates", async () => {
  const writes = [];
  const originalWrite = process.stdout.write;
  process.stdout.write = function patchedWrite(chunk, encoding, callback) {
    writes.push(String(chunk));
    if (typeof encoding === "function") {
      encoding();
    } else if (typeof callback === "function") {
      callback();
    }
    return true;
  };

  const processState = { exitCode: 1 };
  let closed = false;
  try {
    await runCli({
      command: "once",
      args: [],
      config: makeConfig(),
      logger: { info() {}, error() {}, warn() {} },
      processState,
      botFactory: () => ({
        async init() {},
        async close() {
          closed = true;
        },
        async runCycle() {
          return {
            cycleAt: "2026-04-17T00:00:00.000Z",
            entryAttempt: {
              status: "no_allowed_candidates",
              blockedReasons: ["model_confidence_too_low"]
            },
            openedPosition: null
          };
        }
      })
    });
  } finally {
    process.stdout.write = originalWrite;
  }

  assert.equal(processState.exitCode, 0);
  assert.equal(closed, true);
  assert.match(writes.join(""), /no_allowed_candidates/);
});

await runCheck("run cli does not force success exit code when once throws", async () => {
  const processState = { exitCode: 7 };
  let closed = false;
  await assert.rejects(
    runCli({
      command: "once",
      args: [],
      config: makeConfig(),
      logger: { info() {}, error() {}, warn() {} },
      processState,
      botFactory: () => ({
        async init() {},
        async close() {
          closed = true;
        },
        async runCycle() {
          throw new Error("cycle exploded");
        }
      })
    }),
    /cycle exploded/
  );
  assert.equal(processState.exitCode, 7);
  assert.equal(closed, true);
});

