await runCheck("trading bot restores corrupted primary state from backup", async () => {
  const saved = [];
  const quarantined = [];
  const bot = Object.create(TradingBot.prototype);
  bot.store = {
    async loadRuntime() {
      const error = new SyntaxError("Unexpected token");
      error.filePath = "/tmp/runtime.json";
      error.corruptionKind = "invalid_json";
      throw error;
    },
    async loadModelBackups() {
      return [];
    },
    async loadJournal() {
      return { events: [] };
    },
    async loadModel() {
      return { bias: 0, weights: {} };
    },
    async saveRuntime(runtime) {
      saved.push(["runtime", runtime]);
    },
    async saveJournal(journal) {
      saved.push(["journal", journal]);
    },
    async saveModel(model) {
      saved.push(["model", model]);
    },
    async saveModelBackups(backups) {
      saved.push(["modelBackups", backups]);
    },
    async quarantineCorruptFile(filePath) {
      quarantined.push(filePath);
      return `${filePath}.corrupt-2026-03-10T08-11-49.918Z`;
    }
  };
  bot.backupManager = {
    async loadLatestBackup() {
      return {
        at: "2026-03-10T08:11:49.918Z",
        payload: {
          runtime: { lastCycleAt: "2026-03-10T08:00:00.000Z", recovery: {} },
          journal: { events: [] },
          modelState: { bias: 1, weights: { trend: 0.5 } },
          modelBackups: [{ at: "2026-03-09T08:00:00.000Z" }]
        }
      };
    }
  };
  bot.logger = { warn() {} };
  const recovered = await bot.loadPersistedStateWithBackupFallback();
  assert.equal(recovered.runtime.lastCycleAt, "2026-03-10T08:00:00.000Z");
  assert.equal(recovered.runtime.recovery.restoredFromBackupAt, "2026-03-10T08:11:49.918Z");
  assert.equal(recovered.runtime.recovery.corruptPrimaryState.filePath, "/tmp/runtime.json");
  assert.equal(recovered.runtime.recovery.corruptPrimaryState.quarantinedTo, "/tmp/runtime.json.corrupt-2026-03-10T08-11-49.918Z");
  assert.ok(recovered.runtime.service.initWarnings[0].includes("Corrupt primary state recovered from backup"));
  assert.equal(recovered.modelState.bias, 1);
  assert.equal(recovered.modelBackups.length, 1);
  assert.equal(recovered.journal.events.at(-1).type, "state_restored_from_backup");
  assert.equal(recovered.journal.events.at(-1).filePath, "/tmp/runtime.json");
  assert.deepEqual(quarantined, ["/tmp/runtime.json"]);
  assert.deepEqual(saved.map(([kind]) => kind), ["runtime", "journal", "model", "modelBackups"]);
});

await runCheck("trading bot persist snapshots stay consistent across overlapping writes", async () => {
  const bot = Object.create(TradingBot.prototype);
  const writes = [];
  let releaseFirstRuntimeSave;
  const firstRuntimeSave = new Promise((resolve) => {
    releaseFirstRuntimeSave = resolve;
  });
  let runtimeSaveCount = 0;
  bot.store = {
    async saveRuntime(runtime) {
      runtimeSaveCount += 1;
      writes.push(["runtime", runtime.seq, runtime.journalSeq]);
      if (runtimeSaveCount === 1) {
        await firstRuntimeSave;
      }
    },
    async saveJournal(journal) {
      writes.push(["journal", journal.seq]);
    },
    async saveModel(model) {
      writes.push(["model", model.version]);
    },
    async saveModelBackups(backups) {
      writes.push(["modelBackups", backups.at(-1)?.version || null]);
    }
  };
  bot.stream = { getStatus: () => ({ connected: true }) };
  bot.rlPolicy = { getState: () => ({ policySeq: bot.runtime.seq }) };
  bot.dataRecorder = { getSummary: () => ({ recorderSeq: bot.runtime.seq }) };
  bot.backupManager = { getSummary: () => ({ backupSeq: bot.runtime.seq }) };
  bot.model = { getState: () => ({ version: bot.runtime.seq }) };
  bot.modelBackups = [{ version: 1 }];
  bot.runtime = { seq: 1, journalSeq: 1 };
  bot.journal = { seq: 1 };

  const firstPersist = bot.persist();
  await Promise.resolve();
  bot.runtime.seq = 2;
  bot.runtime.journalSeq = 2;
  bot.journal.seq = 2;
  bot.modelBackups = [{ version: 2 }];
  const secondPersist = bot.persist();
  releaseFirstRuntimeSave();
  await Promise.all([firstPersist, secondPersist]);

  assert.deepEqual(writes, [
    ["runtime", 1, 1],
    ["journal", 1],
    ["model", 1],
    ["modelBackups", 1],
    ["runtime", 2, 2],
    ["journal", 2],
    ["model", 2],
    ["modelBackups", 2]
  ]);
});

