await runCheck("trading bot repairs legacy range-grid allocation bias during paper calibration probe", async () => {
  const events = [];
  const bot = Object.create(TradingBot.prototype);
  bot.config = makeConfig({ botMode: "paper", driftCalibrationEceBlock: 0.28 });
  bot.runtime = { selfHeal: { mode: "paper_calibration_probe" } };
  bot.journal = {
    trades: [
      { brokerMode: "paper", strategyFamily: "range_grid", strategyAtEntry: "range_grid_reversion", labelScore: 0.22, netPnlPct: -0.021, exitAt: "2026-04-22T10:00:00.000Z" },
      { brokerMode: "paper", strategyFamily: "range_grid", strategyAtEntry: "range_grid_reversion", labelScore: 0.28, netPnlPct: -0.013, exitAt: "2026-04-22T09:40:00.000Z" },
      { brokerMode: "paper", strategyFamily: "range_grid", strategyAtEntry: "range_grid_reversion", labelScore: 0.35, netPnlPct: 0.001, exitAt: "2026-04-22T09:20:00.000Z" },
      { brokerMode: "paper", strategyFamily: "range_grid", strategyAtEntry: "range_grid_reversion", labelScore: 0.41, netPnlPct: -0.008, exitAt: "2026-04-22T09:00:00.000Z" },
      { brokerMode: "paper", strategyFamily: "range_grid", strategyAtEntry: "range_grid_reversion", labelScore: 0.48, netPnlPct: 0.002, exitAt: "2026-04-22T08:40:00.000Z" },
      { brokerMode: "paper", strategyFamily: "range_grid", strategyAtEntry: "range_grid_reversion", labelScore: 0.44, netPnlPct: -0.004, exitAt: "2026-04-22T08:20:00.000Z" }
    ]
  };
  bot.recordEvent = (type, payload) => events.push({ type, payload });
  let repairCalls = 0;
  bot.model = {
    getStrategyAllocationSummary() {
      return {
        topFamilies: [
          { id: "range_grid", trades: 48, confidence: 0.91 },
          { id: "trend_following", trades: 4, confidence: 0.22 }
        ],
        topStrategies: [
          { id: "range_grid_reversion", trades: 44, confidence: 0.88 }
        ]
      };
    },
    getCalibrationSummary() {
      return { expectedCalibrationError: 0.2841 };
    },
    repairStrategyAllocationLegacyBias(options = {}) {
      repairCalls += 1;
      return {
        applied: true,
        familyId: options.familyId,
        strategyIds: options.strategyIds,
        repairedBucketCount: 5,
        removedTradeWeight: 44
      };
    }
  };
  const result = bot.maybeRepairStrategyAllocationLegacyBias("2026-04-22T10:30:00.000Z");
  assert.equal(result.applied, true);
  assert.equal(repairCalls, 1);
  assert.equal(result.familyId, "range_grid");
  assert.equal(result.strategyIds[0], "range_grid_reversion");
  assert.equal(result.trigger.selfHealMode, "paper_calibration_probe");
  assert.ok(events.some((item) => item.type === "strategy_allocation_legacy_bias_repaired"));
});
