await runCheck("trading bot force reconcile executes a real exchange-truth pass and clears stale force errors", async () => {
  const bot = Object.create(TradingBot.prototype);
  const reconcileCalls = [];
  let savedRuntime = null;
  let lifecycleReason = null;
  let refreshCount = 0;
  bot.config = makeConfig();
  bot.runtime = {
    exchangeTruth: {
      freezeEntries: false,
      mismatchCount: 3,
      reconcileRequiredSymbols: ["ATOMUSDT", "GNOUSDT"],
      manualReviewSymbols: ["ATOMUSDT"],
      lastForceReconcileError: "stale_force_failure"
    },
    orderLifecycle: { pendingActions: [], positions: {}, activeActions: {}, recentTransitions: [], actionJournal: [] },
    ops: {}
  };
  bot.recordEvent = () => {};
  bot.maybeRunExchangeTruthLoop = async (args = {}) => {
    reconcileCalls.push(args);
    bot.runtime.exchangeTruth.freezeEntries = false;
    bot.runtime.exchangeTruth.mismatchCount = 0;
    bot.runtime.exchangeTruth.reconcileRequiredSymbols = [];
    bot.runtime.exchangeTruth.manualReviewSymbols = [];
  };
  bot.syncOrderLifecycleState = (reason) => {
    lifecycleReason = reason;
    return {};
  };
  bot.refreshOperationalViews = () => {
    refreshCount += 1;
  };
  bot.store = {
    saveRuntime: async (runtime) => {
      savedRuntime = runtime;
    }
  };
  bot.getDashboardSnapshot = async () => ({ ok: true, exchangeTruth: bot.runtime.exchangeTruth });

  const snapshot = await TradingBot.prototype.forceReconcile.call(bot, {
    note: "clear stale symbols",
    at: "2026-04-18T12:00:00.000Z"
  });

  assert.equal(reconcileCalls.length, 1);
  assert.equal(reconcileCalls[0].force, true);
  assert.equal(reconcileCalls[0].auditOnly, undefined);
  assert.equal(reconcileCalls[0].now.toISOString(), "2026-04-18T12:00:00.000Z");
  assert.equal(bot.runtime.exchangeTruth.lastForceReconcileAt, "2026-04-18T12:00:00.000Z");
  assert.equal(bot.runtime.exchangeTruth.lastForceReconcileError, null);
  assert.equal(bot.runtime.exchangeTruth.freezeEntries, false);
  assert.deepEqual(bot.runtime.exchangeTruth.reconcileRequiredSymbols, []);
  assert.deepEqual(bot.runtime.exchangeTruth.manualReviewSymbols, []);
  assert.equal(lifecycleReason, "operator_force_reconcile");
  assert.equal(refreshCount, 1);
  assert.equal(savedRuntime, bot.runtime);
  assert.equal(snapshot.ok, true);
});

