await runCheck("offline trainer builds a closed-loop strategy promotion engine from scope evidence", async () => {
  const trainer = new OfflineTrainer(makeConfig({ botMode: "paper" }));
  const nowIso = "2026-04-18T10:00:00.000Z";
  const buildTrade = (id, pnlQuote, netPnlPct, executionQualityScore, labelScore, hoursAgo = 6) => ({
    symbol: "BTCUSDT",
    brokerMode: "paper",
    strategyAtEntry: id,
    strategyFamily: id === "ema_trend" ? "trend_following" : "mean_reversion",
    regimeAtEntry: id === "ema_trend" ? "trend" : "range",
    sessionAtEntry: id === "ema_trend" ? "us" : "asia",
    marketConditionAtEntry: id === "ema_trend" ? "trend_continuation" : "range_reversion",
    pnlQuote,
    netPnlPct,
    executionQualityScore,
    labelScore,
    rawFeatures: { ema_alignment: 1 },
    entryRationale: {
      strategy: {
        activeStrategy: id,
        family: id === "ema_trend" ? "trend_following" : "mean_reversion"
      },
      session: { session: id === "ema_trend" ? "us" : "asia" },
      marketCondition: { conditionId: id === "ema_trend" ? "trend_continuation" : "range_reversion" }
    },
    entryAt: new Date(new Date(nowIso).getTime() - hoursAgo * 60 * 60 * 1000).toISOString(),
    exitAt: new Date(new Date(nowIso).getTime() - (hoursAgo - 1) * 60 * 60 * 1000).toISOString()
  });
  const journal = {
    trades: [
      ...Array.from({ length: 7 }, (_, index) => buildTrade("ema_trend", 18 + index, 0.012 + index * 0.0008, 0.79, 0.74, 10 + index)),
      ...Array.from({ length: 6 }, (_, index) => buildTrade("fade_vwap", -12 - index, -0.009 - index * 0.0007, 0.44, 0.38, 18 + index))
    ]
  };
  const summary = trainer.buildSummary({ journal, dataRecorder: {}, counterfactuals: [], historySummary: {}, nowIso });

  const trendStrategy = (summary.strategyPromotionEngine.strategy || []).find((item) => item.id === "ema_trend");
  const fadeStrategy = (summary.strategyPromotionEngine.strategy || []).find((item) => item.id === "fade_vwap");
  assert.equal(summary.strategyPromotionEngine.status, "ready");
  assert.ok(trendStrategy);
  assert.equal(trendStrategy.state, "favor");
  assert.ok(trendStrategy.priorityBoost > 0);
  assert.ok(fadeStrategy);
  assert.ok(["cool", "suspend"].includes(fadeStrategy.state));
  assert.ok(fadeStrategy.mustImprove.includes("reduce_false_positive_rate"));
});

