await runCheck("stream coordinator restarts the user stream after an unexpected disconnect", async () => {
  const openedUrls = [];
  let listenKeyIndex = 0;
  const originalWebSocket = globalThis.WebSocket;
  class FakeWebSocket {
    constructor(url) {
      this.url = url;
      this.listeners = new Map();
      openedUrls.push(url);
    }

    addEventListener(type, handler) {
      const bucket = this.listeners.get(type) || [];
      bucket.push(handler);
      this.listeners.set(type, bucket);
    }

    emit(type, payload = {}) {
      for (const handler of this.listeners.get(type) || []) {
        handler(payload);
      }
    }

    close() {}
  }
  globalThis.WebSocket = FakeWebSocket;
  let coordinator = null;
  try {
    coordinator = new StreamCoordinator({
      client: {
        async createUserDataListenKey() {
          listenKeyIndex += 1;
          return `listen-${listenKeyIndex}`;
        },
        async keepAliveUserDataListenKey() {
          return true;
        },
        getStreamBaseUrl() {
          return "wss://stream.binance.com:9443";
        },
        getFuturesStreamBaseUrl() {
          return "wss://fstream.binance.com";
        }
      },
      config: makeConfig({ watchlist: ["BTCUSDT"], botMode: "live", binanceApiKey: "key", streamReconnectDelayMs: 1 }),
      logger: { warn() {}, info() {} }
    });
    coordinator.state.enabled = true;
    await coordinator.startUserStream();
    const firstSocket = coordinator.userSocket;
    firstSocket.emit("open");
    firstSocket.emit("close");
    await coordinator.userRestartPromise;
    assert.equal(openedUrls.length, 2);
    assert.equal(listenKeyIndex, 2);
    assert.notEqual(coordinator.userSocket, firstSocket);
    assert.equal(coordinator.state.listenKey, "listen-2");
  } finally {
    if (coordinator) {
      await coordinator.close();
    }
    globalThis.WebSocket = originalWebSocket;
  }
});

await runCheck("stream coordinator uses WebSocket API signature subscription for demo spot user streams", async () => {
  const originalWebSocket = globalThis.WebSocket;
  class FakeWebSocket {
    constructor(url) {
      this.url = url;
      this.listeners = new Map();
      this.sent = [];
    }

    addEventListener(type, handler) {
      const bucket = this.listeners.get(type) || [];
      bucket.push(handler);
      this.listeners.set(type, bucket);
    }

    emit(type, payload = {}) {
      for (const handler of this.listeners.get(type) || []) {
        handler(payload);
      }
    }

    send(payload) {
      this.sent.push(payload);
    }

    close() {}
  }
  globalThis.WebSocket = FakeWebSocket;
  try {
    const client = new BinanceClient({
      apiKey: "test-key",
      apiSecret: "test-secret",
      baseUrl: "https://demo-api.binance.com/api",
      futuresBaseUrl: "https://demo-fapi.binance.com",
      recvWindow: 5000,
      logger: { info() {}, warn() {}, error() {} },
      fetchImpl: async () => ({ ok: true, text: async () => "{}", status: 200 })
    });
    const coordinator = new StreamCoordinator({
      client,
      config: makeConfig({ watchlist: ["BTCUSDT"], botMode: "live", binanceApiKey: "test-key" }),
      logger: { warn() {}, info() {} }
    });
    const pending = coordinator.startUserStream();
    const socket = coordinator.userSocket;
    socket.emit("open");
    const request = JSON.parse(socket.sent[0]);
    assert.equal(socket.url, "wss://demo-ws-api.binance.com/ws-api/v3");
    assert.equal(request.method, "userDataStream.subscribe.signature");
    assert.equal(request.params.apiKey, "test-key");
    socket.emit("message", {
      data: JSON.stringify({
        id: request.id,
        status: 200,
        result: {
          subscriptionId: 7
        }
      })
    });
    await pending;
    const status = coordinator.getStatus();
    assert.equal(status.userStreamConnected, true);
    assert.equal(status.userStreamSessionActive, true);
    assert.equal(status.userStreamTransport, "ws_api");
    assert.equal(Object.prototype.hasOwnProperty.call(status, "listenKey"), false);
    await coordinator.close();
  } finally {
    globalThis.WebSocket = originalWebSocket;
  }
});

await runCheck("stream coordinator restarts the futures stream after an unexpected error", async () => {
  const openedUrls = [];
  const originalWebSocket = globalThis.WebSocket;
  class FakeWebSocket {
    constructor(url) {
      this.url = url;
      this.listeners = new Map();
      openedUrls.push(url);
    }

    addEventListener(type, handler) {
      const bucket = this.listeners.get(type) || [];
      bucket.push(handler);
      this.listeners.set(type, bucket);
    }

    emit(type, payload = {}) {
      for (const handler of this.listeners.get(type) || []) {
        handler(payload);
      }
    }

    close() {}
  }
  globalThis.WebSocket = FakeWebSocket;
  let coordinator = null;
  try {
    coordinator = new StreamCoordinator({
      client: {
        getStreamBaseUrl() {
          return "wss://stream.binance.com:9443";
        },
        getFuturesStreamBaseUrl() {
          return "wss://fstream.binance.com";
        }
      },
      config: makeConfig({ watchlist: ["BTCUSDT"], streamReconnectDelayMs: 1 }),
      logger: { warn() {}, info() {} }
    });
    coordinator.state.enabled = true;
    await coordinator.startFuturesStream();
    const firstSocket = coordinator.futuresSocket;
    firstSocket.emit("open");
    firstSocket.emit("error", { message: "network drop" });
    await coordinator.futuresRestartPromise;
    assert.equal(openedUrls.length, 2);
    assert.notEqual(coordinator.futuresSocket, firstSocket);
  } finally {
    if (coordinator) {
      await coordinator.close();
    }
    globalThis.WebSocket = originalWebSocket;
  }
});

await runCheck("stream coordinator keeps retrying after a restart attempt itself fails", async () => {
  const coordinator = new StreamCoordinator({
    client: {},
    config: makeConfig({ streamReconnectDelayMs: 1 }),
    logger: { warn() {}, info() {} }
  });
  coordinator.state.enabled = true;
  const originalWebSocket = globalThis.WebSocket;
  globalThis.WebSocket = class FakeWebSocket {};
  let attempts = 0;
  try {
    coordinator.scheduleRestart("public", async () => {
      attempts += 1;
      if (attempts === 1) {
        throw new Error("first_restart_failed");
      }
    }, "socket_error");
    await waitForCondition(() => attempts >= 2, {
      timeoutMs: 1200,
      intervalMs: 20,
      description: "second public restart attempt"
    });
    await coordinator.publicRestartPromise;
    const restartHealth = coordinator.getStatus().restartHealth.public;
    assert.equal(attempts, 2);
    assert.equal(restartHealth.attempts, 2);
    assert.equal(restartHealth.failures, 1);
    assert.equal(restartHealth.lastReason, "socket_error_retry");
    assert.equal(restartHealth.stalled, false);
    assert.equal(restartHealth.lastError, null);
  } finally {
    await coordinator.close();
    globalThis.WebSocket = originalWebSocket;
  }
});

