// ─── Protective SELL OCO geometry validator ──────────────────────────────────

await runCheck("protective SELL OCO geometry validator accepts valid geometry", async () => {
  // TP above market, stop below market, limit at-or-below trigger: all good.
  const result = validateProtectiveSellOcoGeometry({
    takeProfitPrice: 105,
    stopTriggerPrice: 95,
    stopLimitPrice: 94.5,
    currentMid: 100,
    currentBid: 99.9,
    currentAsk: 100.1,
    symbol: "BTCUSDT",
    lifecycleState: "protection_pending"
  });
  assert.equal(result.valid, true, `expected valid geometry but got issues: ${result.issues.join(",")}`);
  assert.equal(result.issues.length, 0);
});

await runCheck("protective SELL OCO geometry validator rejects TP below market before OCO submit", async () => {
  // Market has risen above the stored take-profit: geometry is stale/invalid.
  const result = validateProtectiveSellOcoGeometry({
    takeProfitPrice: 95,   // stale — below current market
    stopTriggerPrice: 85,
    stopLimitPrice: 84.5,
    currentMid: 100,
    currentBid: 99.9,
    currentAsk: 100.1,
    symbol: "BTCUSDT",
    lifecycleState: "reconcile_required"
  });
  assert.equal(result.valid, false);
  assert.ok(result.issues.includes("takeProfitPrice_not_above_market"), `expected takeProfitPrice_not_above_market but got: ${result.issues}`);
  assert.equal(result.diagnostics.symbol, "BTCUSDT");
  assert.equal(result.diagnostics.currentMid, 100);

  // Verify buildProtectiveOrderParams throws the structured error with the right code.
  const broker = new LiveBroker({
    client: {},
    config: makeConfig({ enableExchangeProtection: true, liveStopLimitBufferPct: 0.005 }),
    logger: { warn() {}, info() {} },
    symbolRules: { BTCUSDT: rules }
  });
  const position = {
    symbol: "BTCUSDT",
    quantity: 0.001,
    stopLossPrice: 85,
    takeProfitPrice: 95,   // stale — below current market (100)
    lifecycleState: "reconcile_required"
  };
  const snapshot = { book: { bid: 99.9, ask: 100.1, mid: 100 } };
  let caughtError = null;
  try {
    await broker.buildProtectiveOrderParams(position, rules, snapshot);
  } catch (err) {
    caughtError = err;
  }
  assert.ok(caughtError, "expected buildProtectiveOrderParams to throw on invalid geometry");
  assert.equal(caughtError.code, "PROTECTIVE_OCO_GEOMETRY_INVALID");
  assert.equal(caughtError.protectiveOcoGeometryInvalid, true);
  assert.equal(caughtError.symbol, "BTCUSDT");
  assert.ok(Array.isArray(caughtError.issues) && caughtError.issues.includes("takeProfitPrice_not_above_market"));
});

await runCheck("reconcile missing_protection with invalid geometry does not crash and marks position protect_only", async () => {
  // Simulate: position has no protective order, stored TP/SL are stale (market has moved above TP).
  // ensureProtectiveOrder should NOT crash startup — it should mark the position and return a safe audit.
  const broker = new LiveBroker({
    client: {
      getAccountInfo: async () => ({ balances: [{ asset: "BTC", free: "0.001", locked: "0" }, { asset: "USDT", free: "1000", locked: "0" }], canTrade: true, accountType: "SPOT", permissions: [] }),
      getOpenOrders: async () => [],
      getOpenOrderLists: async () => [],
      getMyTrades: async () => []
    },
    config: makeConfig({ enableExchangeProtection: true, liveStopLimitBufferPct: 0.005, enableAutoReconcile: true, allowRecoverUnsyncedPositions: false }),
    logger: { warn() {}, info() {} },
    symbolRules: { BTCUSDT: rules }
  });
  // Position with stale TP below current market — protection rebuild would fail.
  const position = {
    id: "pos-geom-test-1",
    symbol: "BTCUSDT",
    quantity: 0.001,
    entryPrice: 90,
    stopLossPrice: 85,
    takeProfitPrice: 95,   // stale — market is at 100, so TP is below market
    totalCost: 90,
    notional: 90,
    entryFee: 0,
    highestPrice: 90,
    lowestPrice: 90,
    lastMarkedPrice: 90,
    trailingStopPct: 0.01,
    brokerMode: "live",
    lifecycleState: "protection_pending",
    operatorMode: "normal",
    reconcileRequired: false,
    manualReviewRequired: false,
    protectiveOrderListId: null,
    protectiveOrders: []
  };
  const runtime = { openPositions: [position], orderLifecycle: { activeActions: {} } };
  const warnings = [];

  // The decision and evidence mirror what classifyReconcileDecision would produce for missing_protection.
  const { applySafeReconcileAutofix } = await import("../src/execution/liveBrokerReconcile.js");
  const decision = {
    decision: "SAFE_AUTOFIX",
    reason: "missing_protection",
    action: "rebuild_missing_protection",
    autofixKind: "missing_protection",
    shouldRetry: false,
    evidenceSummary: { protectionMissing: true }
  };
  const evidence = {
    exchangeQuantity: 0.001,
    runtimeQuantity: 0.001,
    quantityDiff: 0,
    qtyWithinTolerance: true,
    exchangeProtectiveLists: [],
    attemptCount: 1
  };
  // getMarketSnapshot returns current market: mid=100 makes TP=95 invalid.
  const getMarketSnapshot = async () => ({ book: { bid: 99.9, ask: 100.1, mid: 100 } });
  const settings = { dryRun: false };

  const result = await applySafeReconcileAutofix(broker, {
    position, runtime, rules, decision, evidence, warnings, getMarketSnapshot, settings
  });

  // Must NOT crash, must return a non-crashing audit result.
  assert.ok(result, "applySafeReconcileAutofix should return a result, not throw");
  assert.equal(result.closedTrade, null, "should not produce a closed trade");
  assert.equal(result.audit.decision, "NEEDS_MANUAL_REVIEW", `expected NEEDS_MANUAL_REVIEW but got ${result.audit.decision}`);
  assert.equal(result.audit.reason, "protective_rebuild_geometry_invalid");
  assert.equal(result.audit.protectionBlocked, true);
  assert.equal(result.audit.applied, false);

  // Position must be marked safely, not left in an unhandled state.
  assert.equal(position.reconcileRequired, true, "position.reconcileRequired should be true");
  assert.equal(position.operatorMode, "protect_only", "position.operatorMode should be protect_only");
  assert.equal(position.lifecycleState, "reconcile_required", "position.lifecycleState should be reconcile_required");

  // Warning must include full diagnostics.
  const geomWarning = warnings.find((w) => w.issue === "protective_rebuild_geometry_invalid");
  assert.ok(geomWarning, "warning with issue=protective_rebuild_geometry_invalid should be emitted");
  assert.equal(geomWarning.symbol, "BTCUSDT");
  assert.ok(geomWarning.currentMid != null, "warning should include currentMid");
});

await runCheck("reconcile protective rebuild blocked by stale stop-loss above market marks safe blocked state", async () => {
  // Stop trigger >= currentMid: the stop is ABOVE market — also an invalid SELL OCO.
  const broker = new LiveBroker({
    client: {},
    config: makeConfig({ enableExchangeProtection: true, liveStopLimitBufferPct: 0.005 }),
    logger: { warn() {}, info() {} },
    symbolRules: { BTCUSDT: rules }
  });
  const position = {
    id: "pos-geom-test-2",
    symbol: "BTCUSDT",
    quantity: 0.001,
    entryPrice: 110,
    stopLossPrice: 105,    // stop ABOVE current market (100) — stale after a big drop
    takeProfitPrice: 120,  // TP above market — that part is fine
    totalCost: 110,
    notional: 110,
    lifecycleState: "reconcile_required",
    operatorMode: "normal",
    reconcileRequired: true,
    protectiveOrderListId: null,
    protectiveOrders: []
  };
  const snapshot = { book: { bid: 99.9, ask: 100.1, mid: 100 } };

  // Directly verify the geometry validator detects the stop-above-market issue.
  const { normalizePrice } = await import("../src/binance/symbolFilters.js");
  const stopTriggerPrice = normalizePrice(position.stopLossPrice, rules, "round");
  const stopLimitPrice = normalizePrice(stopTriggerPrice * 0.995, rules, "floor");
  const takeProfitPrice = normalizePrice(position.takeProfitPrice, rules, "round");
  const validation = validateProtectiveSellOcoGeometry({
    takeProfitPrice,
    stopTriggerPrice,
    stopLimitPrice,
    currentMid: snapshot.book.mid,
    currentBid: snapshot.book.bid,
    currentAsk: snapshot.book.ask,
    symbol: position.symbol,
    lifecycleState: position.lifecycleState
  });
  assert.equal(validation.valid, false, `expected geometry invalid but got valid. issues=${validation.issues}`);
  assert.ok(validation.issues.includes("stopTriggerPrice_not_below_market"), `expected stopTriggerPrice_not_below_market but got: ${validation.issues}`);

  // buildProtectiveOrderParams must throw the structured error (not a Binance request).
  let caughtError = null;
  try {
    await broker.buildProtectiveOrderParams(position, rules, snapshot);
  } catch (err) {
    caughtError = err;
  }
  assert.ok(caughtError, "expected buildProtectiveOrderParams to throw on stale stop-loss above market");
  assert.equal(caughtError.code, "PROTECTIVE_OCO_GEOMETRY_INVALID");
  assert.ok(caughtError.issues.includes("stopTriggerPrice_not_below_market"));
  assert.equal(caughtError.currentMid, 100);
  // Ensure the error carries all required diagnostic fields.
  assert.ok("takeProfitPrice" in caughtError, "should carry takeProfitPrice");
  assert.ok("stopTriggerPrice" in caughtError, "should carry stopTriggerPrice");
  assert.ok("stopLimitPrice" in caughtError, "should carry stopLimitPrice");
  assert.ok("currentBid" in caughtError, "should carry currentBid");
  assert.ok("currentAsk" in caughtError, "should carry currentAsk");
  assert.ok("lifecycleState" in caughtError, "should carry lifecycleState");
});

