await runCheck("trading bot falls back to a no-op logger when none is provided", async () => {
  const runtimeDir = await fs.mkdtemp(path.join(os.tmpdir(), "codex-noop-logger-"));
  const bot = new TradingBot({ config: makeConfig({ runtimeDir }), logger: undefined });
  assert.equal(typeof bot.logger.info, "function");
  assert.equal(typeof bot.logger.warn, "function");
  assert.equal(typeof bot.logger.error, "function");
  assert.equal(typeof bot.logger.debug, "function");
  assert.doesNotThrow(() => bot.logger.warn("noop"));
});

